SELECT ?person ?label WHERE {
  ?person p:P39 ?officeStatement.
  ?officeStatement ps:P39 ?office.
  ?office wdt:P127 wd:Q1440.
  ?officeStatement pq:P580 ?start.
  ?officeStatement pq:P582 ?end.
  FILTER (?start <= "1865-01-01"^^xsd:date && (!bound(?end) || ?end >= "1865-01-01"^^xsd:date))
  OPTIONAL { ?person rdfs:label ?label. FILTER (lang(?label) = "en") }
}

